__NAMESPACE__ = "http://www.crossref.org/schema/5.4.0"


@dataclass
class Orcid:
    """
    The ORCID iD for an author.
    """

    class Meta:
        name = "ORCID"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "required": True,
            "pattern": r"https?://orcid.org/[0-9]{4}-[0-9]{4}-[0-9]{4}-[0-9]{3}[X0-9]{1}",
        },
    )
    authenticated: bool = field(
        default=False,
        metadata={
            "type": "Attribute",
        },
    )


@dataclass
class A:
    """
    Content is "Inline" except that anchors shouldn't be nested.
    """

    class Meta:
        name = "a"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "required": True,
        },
    )
    href: Optional[str] = field(
        default=None,
        metadata={
            "type": "Attribute",
        },
    )


@dataclass
class AbbrevTitle:
    """Common abbreviation or abbreviations used when citing a journal.

    It is recommended that periods be included after abbreviated words
    within the title.
    """

    class Meta:
        name = "abbrev_title"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "min_length": 1,
            "max_length": 150,
        },
    )


class AnonymousContributorRole(Enum):
    AUTHOR = "author"
    EDITOR = "editor"
    CHAIR = "chair"
    REVIEWER = "reviewer"
    REVIEW_ASSISTANT = "review-assistant"
    STATS_REVIEWER = "stats-reviewer"
    REVIEWER_EXTERNAL = "reviewer-external"
    READER = "reader"
    TRANSLATOR = "translator"


