@dataclass
class ItemNumber:
    """
    A publisher-assigned number that uniquely identifies the item being registered.
    """

    class Meta:
        name = "item_number"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "required": True,
            "min_length": 1,
            "max_length": 32,
        },
    )
    item_number_type: Optional[str] = field(
        default=None,
        metadata={
            "type": "Attribute",
        },
    )


