@dataclass
class RunningNumber:
    """
    Running numbers to specify the various reports (ex: RC1 to RC4)
    """

    class Meta:
        name = "running_number"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "required": True,
        },
    )


@dataclass
class ScnPolicyRef:
    """
    An individual SCN policy.
    """

    class Meta:
        name = "scn_policy_ref"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "required": True,
            "min_length": 1,
            "max_length": 2048,
            "pattern": r"([hH][tT][tT][pP]|[hH][tT][tT][pP][sS]|[fF][tT][pP])://.*",
        },
    )


@dataclass
class SeriesNumber:
    """
    The series number within a specific published conference discipline.
    """

    class Meta:
        name = "series_number"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "min_length": 1,
            "max_length": 15,
        },
    )


@dataclass
class SeriesTitle:
    """
    Book series title in a citation.
    """

    class Meta:
        name = "series_title"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "required": True,
        },
    )


@dataclass
class SpecialNumbering:
    """Issue level numbering for supplements or special issues.

    Text defining the type of special issue (e.g. "suppl") should be
    included in this element along with the number.
    """

    class Meta:
        name = "special_numbering"
        namespace = "http://www.crossref.org/schema/5.4.0"

    value: str = field(
        default="",
        metadata={
            "min_length": 1,
            "max_length": 15,
        },
    )


