@dataclass
class Body:
    """Container for the main body of a DOI record submission.

    While it is possible to include records for multiple journals,
    books, conferences, or other types of content in a single
    submission, it is not possible to mix content types within a single
    DOI submission.
    """

    class Meta:
        name = "body"
        namespace = "http://www.crossref.org/schema/5.4.0"

    journal: list[Journal] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    book: list[Book] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    conference: list[Conference] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    sa_component: list[SaComponent] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    dissertation: list[Dissertation] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    report_paper: list[ReportPaper] = field(
        default_factory=list,
        metadata={
            "name": "report-paper",
            "type": "Element",
        },
    )
    standard: list[Standard] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    database: list[Database] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    peer_review: list[PeerReview] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    pending_publication: list[PendingPublication] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )
    posted_content: list[PostedContent] = field(
        default_factory=list,
        metadata={
            "type": "Element",
        },
    )


@dataclass
class DoiBatch:
    """Top level element for a metadata record submission.

    This element indicates the start and end of the XML file. The
    version number is fixed to the version of the schema.
    """

    class Meta:
        name = "doi_batch"
        namespace = "http://www.crossref.org/schema/5.4.0"

    head: Optional[Head] = field(
        default=None,
        metadata={
            "type": "Element",
            "required": True,
        },
    )
    body: Optional[Body] = field(
        default=None,
        metadata={
            "type": "Element",
            "required": True,
        },
    )
    version: str = field(
        init=False,
        default="5.4.0",
        metadata={
            "type": "Attribute",
        },
    )
